import React from 'react';
import { useOrderContext } from '../../Cart_Page/contextAPI/OrderCartContext';
import CartItemCard from './Card';
import '../style/CartPage.css';

const CartPage = () => {
    const { order, menu } = useOrderContext();

    const totalCartAmount = Object.keys(order).reduce((total, productName) => {
        const itemDetails = menu.find(item => item.item === productName);
        return itemDetails ? total + (itemDetails.price * order[productName]) : total;
    }, 0);
    const orderLS=localStorage.getItem('order');
  console.log(orderLS);
    return (
        <div className="cart-page">
            <h2>Your Cart</h2>
            <div className="cart-items">
                {Object.keys(orderLS).length === 0 ? (
                    <p>Your cart is empty</p>
                ) : (
                    Object.keys(order).map(productName => {
                        const itemDetails = menu.find(item => item.item === productName);
                        if (!itemDetails) return null;

                        return (
                            <CartItemCard 
                                key={productName}
                                name={itemDetails.item}
                                description={itemDetails.description}
                                price={itemDetails.price}
                                quantity={order[productName]}
                                // image={itemDetails.image}
                            />
                        );
                    })
                )}
            </div>
            <div className="cart-summary">
                <p>Total Amount: ${totalCartAmount.toFixed(2)}</p>
                <button onClick={() => alert("Proceeding to Payment...")} className="checkout-button">
                    Proceed to Payment
                </button>
            </div>
        </div>
    );
};

export default CartPage;
